 1	import type { FC } from 'react';
 2	import HelpTopicSection from 'src/onlineHelp/learningExperience/HelpTopicSection';
 3	import type { LearningExperienceSubTopic } from 'src/onlineHelp/learningExperience/types';
 4	import {
 5	  getClassForListStyle,
 6	  getTextListComponentForListStyle,
 7	} from 'src/onlineHelp/learningExperience/utils';
 8	
 9	import { TextList, TextListItem } from '@patternfly/react-core';
10	import { css } from '@patternfly/react-styles';
11	
12	type HelpSubTopicProps = {
13	  topic: LearningExperienceSubTopic;
14	  noListItem?: boolean;
15	};
16	
17	const HelpSubTopic: FC<HelpSubTopicProps> = ({ noListItem, topic }) => {
18	  const topicElement = (
19	    <>
20	      {topic.title}
21	      {topic.subTopics ? (
22	        <div className="pf-v6-u-ml-lg">
23	          {topic.expandable ? (
24	            topic.subTopics?.map((subTopic, subIndex) => (
25	              <HelpTopicSection key={subTopic.id} topic={subTopic} index={subIndex} />
26	            ))
27	          ) : (
28	            <div className={css('pf-v6-u-mt-sm', getClassForListStyle(topic.subListStyleType))}>
29	              <TextList component={getTextListComponentForListStyle(topic.subListStyleType)}>
30	                {topic.subTopics?.map((subTopic) => (
31	                  <HelpSubTopic topic={subTopic} key={subTopic.id} />
32	                ))}
33	              </TextList>
34	            </div>
35	          )}
36	        </div>
37	      ) : null}
38	    </>
39	  );
40	
41	  return noListItem ? topicElement : <TextListItem>{topicElement}</TextListItem>;
42	};
43	
44	export default HelpSubTopic;

