 1	import { TextListVariants } from '@patternfly/react-core';
 2	import { isEmpty } from '@utils/helpers';
 3	
 4	import { ListStyleType } from './types';
 5	
 6	export const getClassForListStyle = (listStyleType?: ListStyleType): string | undefined =>
 7	  isEmpty(listStyleType) ? undefined : `forklift--learning__list-type--${listStyleType}`;
 8	
 9	export const getTextListComponentForListStyle = (
10	  listStyleType?: ListStyleType,
11	): 'ul' | 'ol' | undefined =>
12	  listStyleType === ListStyleType.DECIMAL || listStyleType === ListStyleType.LOWER_ALPHA
13	    ? TextListVariants.ol
14	    : TextListVariants.ul;

